import { Pipe, PipeTransform } from '@angular/core';

@Pipe
({
  name: 'dateConvertion',
  pure: true,
})
export class DateConvertionPipe implements PipeTransform 
{
  private month: string[]= 
  [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December'
  ];

  transform(inputDate: string): string 
  {
    let dateList: string[]= inputDate.split('-');
    let date= dateList[2]+' '+this.month[Number(dateList[1])- 1]+' '+dateList[0]; 
    return date;
  }

}
