import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';

import { MediaContentComponent } from './components/media-content/media-content.component';
import { MediaDetailComponent } from './components/media-detail/media-detail.component';

const routes: Routes = 
[
  { path: '', redirectTo: 'home', pathMatch: 'full' },
  { path: 'home', component: MediaContentComponent },
  { path: 'detail/:id', component: MediaDetailComponent }
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
